import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.etsy.com/documentation/";
const PLACEHOLDER_VALUE = "c0ffee5afe10ca1c0ffee5af:e10ca15afe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Etsy Open API v3 docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:etsy",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const etsyFirewall = {",
    '  name: "etsy",',
    '  description: "Etsy",',
    "  placeholders: {",
    `    ETSY_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://openapi.etsy.com",',
    "      auth: {",
    "        headers: {",
    '          "x-api-key": "${{ secrets.ETSY_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Etsy firewall config...");
  const ts = generateTypeScript();
  writeOutput("etsy", ts, import.meta.dirname);
}
